    Elements formEls = elements();
    for (Element el : formEls) {
        // contents are form listable, superset of submitable
        if (!el.tag().isFormSubmittable())
            continue;
        // skip disabled form inputs
        if (el.hasAttr("disabled"))
            continue;
        String name = el.attr("name");
        if (name.length() == 0)
            continue;
        String type = el.attr("type");
        // browsers don't submit these
        if (type.equalsIgnoreCase("button") || type.equalsIgnoreCase("image"))
            continue;
        if (el.nameIs("select")) {
            Elements options = el.select("option[selected]");
            boolean set = false;
            for (Element option : options) {
                data.add(HttpConnection.KeyVal.create(name, option.val()));
                set = true;
            }
            if (!set) {
                Element option = el.selectFirst("option");
                if (option != null)
                    data.add(HttpConnection.KeyVal.create(name, option.val()));
            }
        } else if ("checkbox".equalsIgnoreCase(type) || "radio".equalsIgnoreCase(type)) {
            // only add checkbox or radio if they have the checked attribute
            if (el.hasAttr("checked")) {
                final String val = el.val().length() > 0 ? el.val() : "on";
                data.add(HttpConnection.KeyVal.create(name, val));
            }
        } else {
            data.add(HttpConnection.KeyVal.create(name, el.val()));
        }
    }
    return data;
}

